import{_ as t,o as i,c as a,a2 as s}from"./chunks/framework.jWxB9oXr.js";const u=JSON.parse(`{"title":"FAQ","description":"Frequently asked questions about Silvery — installation, Ink compatibility, performance, components, testing, and terminal support.","frontmatter":{"title":"FAQ","description":"Frequently asked questions about Silvery — installation, Ink compatibility, performance, components, testing, and terminal support.","faq":[{"q":"What is Silvery?","a":"Polished terminal apps in React. Silvery provides 45+ components, layout-first rendering with per-node dirty tracking, responsive layout via useBoxRect(), and full support for modern terminal protocols. Three principles guide the project: take the best from the web, stay true to the terminal, and raise the bar for developer ergonomics, architecture composability, and performance. It works with Bun and Node.js (23.6+)."},{"q":"How does Silvery compare to Ink?","a":"Both use React for terminal UIs. Silvery's key differences are layout-first rendering (components know their size during render via useBoxRect()), comparable performance with different strengths (Silvery faster on cursor/selection, Ink faster on content updates), bundle-parity with Ink+Yoga (114.9 KB vs 116.6 KB gzipped), a larger component library (45+ vs Ink's 6 core + @inkjs/ui's 13), and comprehensive terminal protocol support (Kitty keyboard, SGR mouse, graphics, synchronized output). Ink has a larger ecosystem and is the established standard."},{"q":"Is Silvery compatible with existing Ink code?","a":"Yes. Silvery provides a compatibility layer via silvery/ink and silvery/chalk that passes ~99% of Ink 7.0's test suite (918/931 tests). Most Ink code works with import path changes. See the migration guide for details."},{"q":"How fast is Silvery compared to Ink?","a":"Silvery is 3–27× faster depending on the scenario (up to 20× on memo'd interactive updates). Both are fast enough for 60fps at typical terminal sizes. The cell-level output phase also emits 10-20x less output than Ink's line-level diff on incremental updates. See the detailed benchmarks on the Silvery vs Ink page."},{"q":"What components does Silvery include?","a":"45+ components across layout (Box, SplitView, Divider), input (TextInput, TextArea, SelectList, CommandPalette, Form), display (Text, Badge, Spinner, ProgressBar, Table, Tabs, Toast), navigation (TreeView, ListView, VirtualList, Breadcrumb), and containers (Screen, ModalDialog, ScrollbackView). See the component catalog for the full list."},{"q":"Does Silvery work with Node.js and Bun?","a":"Yes. Silvery is pure TypeScript with no native dependencies or WASM. It works with Bun (any version) and Node.js 23.6+ (which has native TypeScript type stripping)."},{"q":"How do I test Silvery apps?","a":"Silvery provides two testing approaches. For fast unit tests, use createRenderer() from @silvery/test for headless rendering with text assertions. For full terminal verification (ANSI output, colors, scrollback, cursor positioning), use createTermless() which runs a real xterm.js emulator in-process."},{"q":"Does Silvery support mouse input?","a":"Yes. Silvery supports X10, button event tracking, and SGR extended mouse protocol (coordinates beyond 223). Components can handle onClick, onMouseDown, onMouseUp, and onMouseMove. Focus in/out reporting and mouse cursor shape (via OSC 22) are also supported."},{"q":"What terminal emulators does Silvery support?","a":"Silvery works with any terminal that supports basic ANSI escape sequences. Modern features like Kitty keyboard protocol, truecolor, synchronized output, and graphics are auto-detected at startup and enabled when available. Tested with Ghostty, Kitty, iTerm2, WezTerm, Alacritty, Windows Terminal, and others. See terminfo.dev for detailed compatibility data."},{"q":"How does theming work in Silvery?","a":"Silvery ships 38 color palettes with semantic tokens ($primary, $success, $muted, $danger, etc.). Themes auto-detect the terminal's background color and adjust for WCAG-compliant contrast. Use ThemeProvider to set a palette, then reference tokens in your components. See the styling guide and theme explorer for details."},{"q":"Is Silvery production-ready?","a":"Silvery is actively developed and used in production by a complex TUI application with thousands of nodes, multiple views, and rich interactions. The API surface is stabilizing but may have breaking changes before 1.0. It ships with comprehensive tests, including property-invariant fuzz tests for the rendering pipeline."},{"q":"Does Silvery have TypeScript support?","a":"Silvery is written entirely in TypeScript with strict mode enabled. All components, hooks, and APIs are fully typed. The package ships TypeScript source directly (no compiled JavaScript), which works with Bun natively and Node.js 23.6+ with type stripping."},{"q":"How does the layout engine work?","a":"Silvery uses Flexily, a Yoga-compatible flexbox layout engine written in pure TypeScript. Layout runs before rendering, so components can access their dimensions via useBoxRect(). This enables responsive layouts, native scrollable containers, and automatic text truncation without post-render measurement."},{"q":"Can I use Silvery for fullscreen terminal apps?","a":"Yes. Silvery supports both fullscreen mode (alternate screen buffer, absolute positioning, incremental diff) and inline mode (normal scrollback, relative positioning). Fullscreen is the default. Both modes use incremental rendering for efficient updates."},{"q":"How do I migrate from Ink to Silvery?","a":"Most Ink code works with minimal changes. Replace ink imports with silvery/ink, chalk with silvery/chalk, and you're running. For new code, use Silvery's native APIs (useBoxRect, SelectList, VirtualList) to take advantage of responsive layout and the full component library. See the migration guide for step-by-step instructions."}],"head":[["meta",{"property":"og:title","content":"FAQ"}],["meta",{"property":"og:description","content":"Frequently asked questions about Silvery — installation, Ink compatibility, performance, components, testing, and terminal support."}],["meta",{"property":"og:url","content":"https://silvery.dev/guide/faq.html"}],["link",{"rel":"canonical","href":"https://silvery.dev/guide/faq.html"}],["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"BreadcrumbList\\",\\"itemListElement\\":[{\\"@type\\":\\"ListItem\\",\\"position\\":1,\\"name\\":\\"Home\\",\\"item\\":\\"https://silvery.dev/\\"},{\\"@type\\":\\"ListItem\\",\\"position\\":2,\\"name\\":\\"Guide\\",\\"item\\":\\"https://silvery.dev/guide\\"},{\\"@type\\":\\"ListItem\\",\\"position\\":3,\\"name\\":\\"FAQ\\",\\"item\\":\\"https://silvery.dev/guide/faq\\"}]}"],["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"TechArticle\\",\\"headline\\":\\"FAQ\\",\\"description\\":\\"Frequently asked questions about Silvery — installation, Ink compatibility, performance, components, testing, and terminal support.\\",\\"url\\":\\"https://silvery.dev/guide/faq.html\\",\\"dateModified\\":\\"2026-04-10T21:39:01.000Z\\",\\"datePublished\\":\\"2026-04-10T21:39:01.000Z\\",\\"image\\":\\"https://silvery.dev/og-image.png\\",\\"author\\":{\\"@type\\":\\"Person\\",\\"name\\":\\"Bjørn Stabell\\",\\"url\\":\\"https://beorn.codes\\",\\"sameAs\\":[\\"https://github.com/beorn\\"]}}"],["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"FAQPage\\",\\"mainEntity\\":[{\\"@type\\":\\"Question\\",\\"name\\":\\"What is Silvery?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"Polished terminal apps in React. Silvery provides 45+ components, layout-first rendering with per-node dirty tracking, responsive layout via useBoxRect(), and full support for modern terminal protocols. Three principles guide the project: take the best from the web, stay true to the terminal, and raise the bar for developer ergonomics, architecture composability, and performance. It works with Bun and Node.js (23.6+).\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"How does Silvery compare to Ink?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"Both use React for terminal UIs. Silvery's key differences are layout-first rendering (components know their size during render via useBoxRect()), comparable performance with different strengths (Silvery faster on cursor/selection, Ink faster on content updates), bundle-parity with Ink+Yoga (114.9 KB vs 116.6 KB gzipped), a larger component library (45+ vs Ink's 6 core + @inkjs/ui's 13), and comprehensive terminal protocol support (Kitty keyboard, SGR mouse, graphics, synchronized output). Ink has a larger ecosystem and is the established standard.\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"Is Silvery compatible with existing Ink code?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"Yes. Silvery provides a compatibility layer via silvery/ink and silvery/chalk that passes ~99% of Ink 7.0's test suite (918/931 tests). Most Ink code works with import path changes. See the migration guide for details.\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"How fast is Silvery compared to Ink?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"Silvery is 3–27× faster depending on the scenario (up to 20× on memo'd interactive updates). Both are fast enough for 60fps at typical terminal sizes. The cell-level output phase also emits 10-20x less output than Ink's line-level diff on incremental updates. See the detailed benchmarks on the Silvery vs Ink page.\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"What components does Silvery include?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"45+ components across layout (Box, SplitView, Divider), input (TextInput, TextArea, SelectList, CommandPalette, Form), display (Text, Badge, Spinner, ProgressBar, Table, Tabs, Toast), navigation (TreeView, ListView, VirtualList, Breadcrumb), and containers (Screen, ModalDialog, ScrollbackView). See the component catalog for the full list.\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"Does Silvery work with Node.js and Bun?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"Yes. Silvery is pure TypeScript with no native dependencies or WASM. It works with Bun (any version) and Node.js 23.6+ (which has native TypeScript type stripping).\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"How do I test Silvery apps?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"Silvery provides two testing approaches. For fast unit tests, use createRenderer() from @silvery/test for headless rendering with text assertions. For full terminal verification (ANSI output, colors, scrollback, cursor positioning), use createTermless() which runs a real xterm.js emulator in-process.\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"Does Silvery support mouse input?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"Yes. Silvery supports X10, button event tracking, and SGR extended mouse protocol (coordinates beyond 223). Components can handle onClick, onMouseDown, onMouseUp, and onMouseMove. Focus in/out reporting and mouse cursor shape (via OSC 22) are also supported.\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"What terminal emulators does Silvery support?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"Silvery works with any terminal that supports basic ANSI escape sequences. Modern features like Kitty keyboard protocol, truecolor, synchronized output, and graphics are auto-detected at startup and enabled when available. Tested with Ghostty, Kitty, iTerm2, WezTerm, Alacritty, Windows Terminal, and others. See terminfo.dev for detailed compatibility data.\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"How does theming work in Silvery?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"Silvery ships 38 color palettes with semantic tokens ($primary, $success, $muted, $danger, etc.). Themes auto-detect the terminal's background color and adjust for WCAG-compliant contrast. Use ThemeProvider to set a palette, then reference tokens in your components. See the styling guide and theme explorer for details.\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"Is Silvery production-ready?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"Silvery is actively developed and used in production by a complex TUI application with thousands of nodes, multiple views, and rich interactions. The API surface is stabilizing but may have breaking changes before 1.0. It ships with comprehensive tests, including property-invariant fuzz tests for the rendering pipeline.\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"Does Silvery have TypeScript support?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"Silvery is written entirely in TypeScript with strict mode enabled. All components, hooks, and APIs are fully typed. The package ships TypeScript source directly (no compiled JavaScript), which works with Bun natively and Node.js 23.6+ with type stripping.\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"How does the layout engine work?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"Silvery uses Flexily, a Yoga-compatible flexbox layout engine written in pure TypeScript. Layout runs before rendering, so components can access their dimensions via useBoxRect(). This enables responsive layouts, native scrollable containers, and automatic text truncation without post-render measurement.\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"Can I use Silvery for fullscreen terminal apps?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"Yes. Silvery supports both fullscreen mode (alternate screen buffer, absolute positioning, incremental diff) and inline mode (normal scrollback, relative positioning). Fullscreen is the default. Both modes use incremental rendering for efficient updates.\\"}},{\\"@type\\":\\"Question\\",\\"name\\":\\"How do I migrate from Ink to Silvery?\\",\\"acceptedAnswer\\":{\\"@type\\":\\"Answer\\",\\"text\\":\\"Most Ink code works with minimal changes. Replace ink imports with silvery/ink, chalk with silvery/chalk, and you're running. For new code, use Silvery's native APIs (useBoxRect, SelectList, VirtualList) to take advantage of responsive layout and the full component library. See the migration guide for step-by-step instructions.\\"}}]}"]]},"headers":[],"relativePath":"guide/faq.md","filePath":"guide/faq.md","lastUpdated":1775857141000}`),o={name:"guide/faq.md"};function r(n,e,l,p,d,h){return i(),a("div",null,[...e[0]||(e[0]=[s(`<div style="display:none;" hidden="true" aria-hidden="true">Are you an LLM? You can read better optimized documentation at /guide/faq.md for this page in Markdown format</div><h1 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h1><p>Frequently asked questions about Silvery.</p><h2 id="what-is-silvery" tabindex="-1">What is Silvery? <a class="header-anchor" href="#what-is-silvery" aria-label="Permalink to &quot;What is Silvery?&quot;">​</a></h2><p>Polished terminal apps in React. Silvery provides 45+ components, layout-first rendering with per-node dirty tracking, responsive layout via <code>useBoxRect()</code>, and full support for modern terminal protocols. It works with Bun and Node.js (23.6+).</p><p>If you know React, you know Silvery -- the core API (<code>Box</code>, <code>Text</code>, <code>useInput</code>, <code>render</code>) is familiar. What&#39;s different is the rendering pipeline: layout runs first, so components know their size during <a href="/api/render" class="hover-link" data-tooltip="Mount a React tree into a terminal with incremental rendering">render</a>, and only changed nodes are re-rendered.</p><p>Three principles guide the project: take the best from the web, stay true to the terminal, and raise the bar for developer ergonomics, architecture composability, and performance.</p><h2 id="how-does-silvery-compare-to-ink" tabindex="-1">How does Silvery compare to Ink? <a class="header-anchor" href="#how-does-silvery-compare-to-ink" aria-label="Permalink to &quot;How does Silvery compare to Ink?&quot;">​</a></h2><p>Both use React for terminal UIs. Silvery differs in several key ways:</p><ul><li><strong>Layout-first rendering</strong> — layout runs before content <a href="/api/render" class="hover-link" data-tooltip="Mount a React tree into a terminal with incremental rendering">render</a>, so components know their size during <a href="/api/render" class="hover-link" data-tooltip="Mount a React tree into a terminal with incremental rendering">render</a> via <code>useBoxRect()</code>. No components rendering at <code>width: 0</code>, no cascading measure→rerender cycles. See <a href="/guide/silvery-vs-ink.html#responsive-layout">Silvery vs Ink</a>.</li><li><strong>Fast <span class="glossary-hint" data-tooltip="Only re-rendering cells that changed between frames — 100x+ faster than full redraws">incremental rendering</span></strong> — cell-level dirty tracking. 3–27× faster (typically 15–20×) than <a href="/guide/silvery-vs-ink" class="hover-link" data-tooltip="React-based terminal UI framework by Vadim Demedes — the established standard for React CLIs">Ink</a> in our mounted rerender benchmarks. See the <a href="/guide/silvery-vs-ink.html#performance--size">detailed benchmarks</a>.</li><li><strong>Bundle parity with <a href="/guide/silvery-vs-ink" class="hover-link" data-tooltip="React-based terminal UI framework by Vadim Demedes — the established standard for React CLIs">Ink</a>+<a href="/guide/layout-engine" class="hover-link" data-tooltip="Facebook&#39;s WASM-based flexbox layout engine — alternative to Flexily">Yoga</a></strong> — 114.9 KB gzipped runtime vs <a href="/guide/silvery-vs-ink" class="hover-link" data-tooltip="React-based terminal UI framework by Vadim Demedes — the established standard for React CLIs">Ink</a>+<a href="/guide/layout-engine" class="hover-link" data-tooltip="Facebook&#39;s WASM-based flexbox layout engine — alternative to Flexily">Yoga</a>&#39;s 116.6 KB. Pure TypeScript, zero <a href="/guide/silvery-vs-ink#performance-size" class="hover-link" data-tooltip="WebAssembly — Ink uses Yoga compiled to WASM for layout. Silvery uses pure TypeScript (Flexily) by default, with optional Yoga WASM.">WASM</a>, zero native dependencies.</li><li><strong>Larger component library</strong> — 45+ components (vs <a href="/guide/silvery-vs-ink" class="hover-link" data-tooltip="React-based terminal UI framework by Vadim Demedes — the established standard for React CLIs">Ink</a>&#39;s 6 core + <a href="https://github.com/vadimdemedes/ink-ui" target="_blank" rel="noreferrer">@inkjs/ui</a>&#39;s 13), including <a href="/api/virtual-list" class="hover-link" data-tooltip="Efficient rendering for large lists — only visible items are mounted">VirtualList</a>, <a href="/api/command-palette" class="hover-link" data-tooltip="VS Code-style fuzzy command palette with keyboard navigation">CommandPalette</a>, <a href="/components/TreeView" class="hover-link" data-tooltip="Expandable/collapsible tree navigation component">TreeView</a>, <a href="/components/SplitView" class="hover-link" data-tooltip="Resizable split panes component">SplitView</a>, <a href="/api/table" class="hover-link" data-tooltip="Column-aligned table component with headers and auto-sizing">Table</a>, and <a href="/components/Form" class="hover-link" data-tooltip="Vertical form layout with labeled fields, validation, and submit handling">Form</a></li><li><strong>Terminal protocol support</strong> — <a href="/reference/terminal-protocols" class="hover-link" data-tooltip="Extended keyboard protocol with 5 flags — disambiguate, event types, alternate keys, all keys, associated text. Enables modifier detection and key release events.">Kitty keyboard</a>, <a href="/guide/event-handling" class="hover-link" data-tooltip="Extended mouse protocol (mode 1006) — reports coordinates beyond column 223, supports press/release/drag/wheel events.">SGR mouse</a>, <a href="/reference/terminal-protocols" class="hover-link" data-tooltip="DEC mode 2026 — wraps frame emission so the terminal paints atomically. Prevents tearing in tmux, Zellij, and other multiplexers.">synchronized output</a> (DEC 2026), Sixel/Kitty graphics, clipboard, and more</li><li><strong>Dynamic inline <a href="/guide/scrolling" class="hover-link" data-tooltip="Terminal history buffer above the visible viewport — content that scrolled off-screen">scrollback</a></strong> — live React zone at the bottom, completed items graduate to terminal-owned <a href="/guide/scrolling" class="hover-link" data-tooltip="Terminal history buffer above the visible viewport — content that scrolled off-screen">scrollback</a>. Cmd+F works natively.</li></ul><p><a href="/guide/silvery-vs-ink" class="hover-link" data-tooltip="React-based terminal UI framework by Vadim Demedes — the established standard for React CLIs">Ink</a> has a larger ecosystem (~1.3M weekly downloads, 50+ community components) and is the established standard. For a detailed breakdown, see <a href="/guide/silvery-vs-ink.html">Silvery vs Ink</a>.</p><h2 id="is-silvery-compatible-with-existing-ink-code" tabindex="-1">Is Silvery compatible with existing Ink code? <a class="header-anchor" href="#is-silvery-compatible-with-existing-ink-code" aria-label="Permalink to &quot;Is Silvery compatible with existing Ink code?&quot;">​</a></h2><p>Yes. Silvery provides compatibility layers via <code>silvery/ink</code> and <code>silvery/chalk</code> that pass ~99% of <a href="/guide/silvery-vs-ink" class="hover-link" data-tooltip="React-based terminal UI framework by Vadim Demedes — the established standard for React CLIs">Ink</a> 7.0&#39;s test suite (918/931 tests). Most <a href="/guide/silvery-vs-ink" class="hover-link" data-tooltip="React-based terminal UI framework by Vadim Demedes — the established standard for React CLIs">Ink</a> code works by changing import paths:</p><div class="language-ts vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">ts</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// Before</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">import</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> { Box, Text } </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">from</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;ink&quot;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">import</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> chalk </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">from</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;chalk&quot;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// After</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">import</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> { Box, Text } </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">from</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;silvery/ink&quot;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">import</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> chalk </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">from</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;silvery/chalk&quot;</span></span></code></pre></div><p>For new code, use Silvery&#39;s native APIs to take advantage of responsive layout and the full component library. See the <a href="/getting-started/migrate-from-ink.html">migration guide</a> for step-by-step instructions.</p><h2 id="how-fast-is-silvery-compared-to-ink" tabindex="-1">How fast is Silvery compared to Ink? <a class="header-anchor" href="#how-fast-is-silvery-compared-to-ink" aria-label="Permalink to &quot;How fast is Silvery compared to Ink?&quot;">​</a></h2><p>Silvery is <strong>3–27× faster (typically 15–20×)</strong> than <a href="/guide/silvery-vs-ink" class="hover-link" data-tooltip="React-based terminal UI framework by Vadim Demedes — the established standard for React CLIs">Ink</a> 7.0 in our mounted rerender benchmarks. Both frameworks keep a mounted app and call <code>rerender()</code>.</p><table tabindex="0"><thead><tr><th>Scenario</th><th>Silvery advantage</th></tr></thead><tbody><tr><td>Cursor move 20-item (all visible)</td><td><strong>2.7×</strong></td></tr><tr><td>Cursor move 100-item</td><td><strong>3.1×</strong></td></tr><tr><td>Kanban move editing marker</td><td><strong>3.3×</strong></td></tr><tr><td>Memo&#39;d cursor highlight 100 (inverse)</td><td><strong>5.3×</strong></td></tr><tr><td>Memo&#39;d cursor highlight 1000 (inverse)</td><td><strong>6.1×</strong></td></tr><tr><td>Memo&#39;d 100-item single toggle</td><td><strong>5.1×</strong></td></tr><tr><td>Memo&#39;d 500-item single toggle</td><td><strong>5.7×</strong></td></tr><tr><td>Memo&#39;d kanban 5×20 move editing marker</td><td><strong>4.3×</strong></td></tr></tbody></table><p>Both are fast enough for 60fps at typical terminal sizes. Silvery&#39;s cell-level dirty tracking and per-node skip give it an advantage across all mounted workloads.</p><p>Beyond CPU time, Silvery&#39;s cell-level <span class="glossary-hint" data-tooltip="Final rendering stage — diffs terminal buffers and emits minimal ANSI escape sequences">output phase</span> emits <strong>10–20× less output</strong> to the terminal than <a href="/guide/silvery-vs-ink" class="hover-link" data-tooltip="React-based terminal UI framework by Vadim Demedes — the established standard for React CLIs">Ink</a>&#39;s line-level diff on incremental updates.</p><p>Methodology: synchronous rerender throughput. <a href="/guide/silvery-vs-ink" class="hover-link" data-tooltip="React-based terminal UI framework by Vadim Demedes — the established standard for React CLIs">Ink</a> <code>debug: true</code> (no throttle), <code>incrementalRendering: true</code>. Silvery uses <code>@silvery/test</code> <code>createRenderer</code> (production <a href="/api/render" class="hover-link" data-tooltip="Mount a React tree into a terminal with incremental rendering">render</a> core). Both use mocked stdout. See the <a href="/guide/silvery-vs-ink.html#performance--size">full benchmarks</a> for details.</p><h2 id="what-components-does-silvery-include" tabindex="-1">What components does Silvery include? <a class="header-anchor" href="#what-components-does-silvery-include" aria-label="Permalink to &quot;What components does Silvery include?&quot;">​</a></h2><p>45+ components across several categories:</p><ul><li><strong>Layout:</strong> <a href="/api/box" class="hover-link" data-tooltip="Primary layout component — CSS flexbox container with borders, padding, scrolling">Box</a>, <a href="/api/spacer" class="hover-link" data-tooltip="Utility component that expands to fill available space — like CSS flex-grow: 1.">Spacer</a>, <a href="/components/Fill" class="hover-link" data-tooltip="Measures available space and passes dimensions to children via render prop">Fill</a>, <a href="/guide/silvery-vs-ink#both-have" class="hover-link" data-tooltip="Utility component that renders a newline character — equivalent to a line break in terminal output.">Newline</a>, <a href="/components/Divider" class="hover-link" data-tooltip="Horizontal line separator with optional title label">Divider</a>, <a href="/components/SplitView" class="hover-link" data-tooltip="Resizable split panes component">SplitView</a></li><li><strong>Input:</strong> <a href="/api/text-input" class="hover-link" data-tooltip="Single-line text input with built-in readline (Ctrl+A/E/K/U, Alt+B/F)">TextInput</a>, <a href="/api/text-area" class="hover-link" data-tooltip="Multi-line text editing with cursor movement, selection, and word wrap">TextArea</a>, <a href="/api/select-list" class="hover-link" data-tooltip="Interactive keyboard-navigable list — j/k, arrows, Enter, type-ahead search">SelectList</a>, <a href="/api/command-palette" class="hover-link" data-tooltip="VS Code-style fuzzy command palette with keyboard navigation">CommandPalette</a>, <a href="/components/Form" class="hover-link" data-tooltip="Vertical form layout with labeled fields, validation, and submit handling">Form</a>, <a href="/components/Toggle" class="hover-link" data-tooltip="Boolean switch with label — keyboard-togglable on/off control">Toggle</a>, <a href="/components/SearchBar" class="hover-link" data-tooltip="Integrated search input — activates via / or Ctrl+F with match highlighting">SearchBar</a></li><li><strong>Display:</strong> <a href="/api/text" class="hover-link" data-tooltip="Styled text component with color, bold, italic, underline, and wrapping">Text</a>, <a href="/components/Badge" class="hover-link" data-tooltip="Styled status label with variant colors (success, error, warning, primary)">Badge</a>, <a href="/api/spinner" class="hover-link" data-tooltip="Animated loading indicator with customizable frames">Spinner</a>, <a href="/api/progress-bar" class="hover-link" data-tooltip="Determinate/indeterminate progress indicator with theming">ProgressBar</a>, <a href="/api/table" class="hover-link" data-tooltip="Column-aligned table component with headers and auto-sizing">Table</a>, <a href="/api/tabs" class="hover-link" data-tooltip="Tabbed navigation component with keyboard support">Tabs</a>, <a href="/components/Toast" class="hover-link" data-tooltip="Auto-dismiss notification component">Toast</a>, Tooltip, <a href="/components/Skeleton" class="hover-link" data-tooltip="Placeholder loading indicator — animated shimmer effect for content not yet loaded">Skeleton</a></li><li><strong>Navigation:</strong> <a href="/components/TreeView" class="hover-link" data-tooltip="Expandable/collapsible tree navigation component">TreeView</a>, <a href="/api/list-view" class="hover-link" data-tooltip="Virtualized list with pluggable cache, navigation, and search">ListView</a>, <a href="/api/virtual-list" class="hover-link" data-tooltip="Efficient rendering for large lists — only visible items are mounted">VirtualList</a>, <a href="/components/Breadcrumb" class="hover-link" data-tooltip="Navigation breadcrumb trail with configurable separator">Breadcrumb</a></li><li><strong>Containers:</strong> <a href="/components/Screen" class="hover-link" data-tooltip="Root layout component — fills the terminal viewport with flexbox column layout">Screen</a>, <a href="/components/ModalDialog" class="hover-link" data-tooltip="Modal overlay with focus trapping and automatic theme">ModalDialog</a>, <a href="/components/PickerDialog" class="hover-link" data-tooltip="Modal selection dialog — fuzzy-searchable list with keyboard navigation">PickerDialog</a>, <a href="/components/ScrollbackView" class="hover-link" data-tooltip="Streaming content display for chat, logs, and agent output">ScrollbackView</a>, <a href="/components/ScrollbackList" class="hover-link" data-tooltip="Streaming list where completed items freeze into terminal scrollback">ScrollbackList</a>, <a href="/components/ErrorBoundary" class="hover-link" data-tooltip="Catches render errors in children and displays a fallback UI">ErrorBoundary</a>, <a href="/components/Console" class="hover-link" data-tooltip="Displays captured console.log/warn/error output inside the TUI">Console</a></li></ul><p>See the <a href="/guides/components.html">component catalog</a> for usage examples and API documentation.</p><h2 id="does-silvery-work-with-node-js-and-bun" tabindex="-1">Does Silvery work with Node.js and Bun? <a class="header-anchor" href="#does-silvery-work-with-node-js-and-bun" aria-label="Permalink to &quot;Does Silvery work with Node.js and Bun?&quot;">​</a></h2><p>Yes. Silvery is pure TypeScript with no native dependencies or <a href="/guide/silvery-vs-ink#performance-size" class="hover-link" data-tooltip="WebAssembly — Ink uses Yoga compiled to WASM for layout. Silvery uses pure TypeScript (Flexily) by default, with optional Yoga WASM.">WASM</a>. It works with:</p><ul><li><strong>Bun</strong> -- any version, natively handles TypeScript</li><li><strong>Node.js 23.6+</strong> -- uses native TypeScript type stripping (no compilation step)</li></ul><p>The package ships TypeScript source directly. There is no build step, no <code>dist/</code> directory, and no compiled JavaScript.</p><h2 id="how-do-i-test-silvery-apps" tabindex="-1">How do I test Silvery apps? <a class="header-anchor" href="#how-do-i-test-silvery-apps" aria-label="Permalink to &quot;How do I test Silvery apps?&quot;">​</a></h2><p>Silvery provides two testing approaches:</p><p><strong>Fast unit tests</strong> with <code>createRenderer()</code> from <code>@silvery/test</code>. This is a headless renderer that produces stripped text output for assertions:</p><div class="language-tsx vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">tsx</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">import</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> { createRenderer } </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">from</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;@silvery/test&quot;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">const</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> app</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> createRenderer</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(&lt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">MyComponent</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> /&gt;)</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">expect</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(app.text).</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">toContain</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;Hello&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre></div><p><strong>Full terminal tests</strong> with <code>createTermless()</code>, which runs a real xterm.js terminal emulator in-process. This verifies actual ANSI output, colors, <a href="/guide/scrolling" class="hover-link" data-tooltip="Terminal history buffer above the visible viewport — content that scrolled off-screen">scrollback</a>, and cursor positioning:</p><div class="language-tsx vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">tsx</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">import</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> { createTermless } </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">from</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;@silvery/test&quot;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">import</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> { run } </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">from</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;silvery/runtime&quot;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">using</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> term</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> createTermless</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">({ cols: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">80</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, rows: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">24</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> })</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">const</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> handle</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> await</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> run</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(&lt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">App</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> /&gt;, term)</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">expect</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(term.screen).</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">toContainText</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;Hello&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre></div><p>See the <a href="/guide/testing.html">testing guide</a> for more patterns.</p><h2 id="does-silvery-support-mouse-input" tabindex="-1">Does Silvery support mouse input? <a class="header-anchor" href="#does-silvery-support-mouse-input" aria-label="Permalink to &quot;Does Silvery support mouse input?&quot;">​</a></h2><p>Yes. Silvery supports the full SGR extended mouse protocol:</p><ul><li><strong>Click events:</strong> <code>onClick</code>, <code>onMouseDown</code>, <code>onMouseUp</code> on <a href="/api/box" class="hover-link" data-tooltip="Primary layout component — CSS flexbox container with borders, padding, scrolling">Box</a> components</li><li><strong>Movement:</strong> <code>onMouseMove</code> for hover effects and drag interactions</li><li><strong>Scroll:</strong> Mouse wheel events via the mouse protocol</li><li><strong>Extended coordinates:</strong> SGR mode supports coordinates beyond column/row 223</li><li><strong>Focus reporting:</strong> Focus in/out events when the terminal window gains or loses focus</li><li><strong>Cursor shape:</strong> OSC 22 mouse cursor shape control (pointer, text, crosshair)</li></ul><p>Mouse support is auto-detected and enabled when the terminal supports it.</p><h2 id="what-terminal-emulators-does-silvery-support" tabindex="-1">What terminal emulators does Silvery support? <a class="header-anchor" href="#what-terminal-emulators-does-silvery-support" aria-label="Permalink to &quot;What terminal emulators does Silvery support?&quot;">​</a></h2><p>Silvery works with any terminal that supports basic <a href="https://terminfo.dev/fundamentals/anatomy" class="hover-link" data-tooltip="Control codes starting with ESC that tell terminals to set colors, move cursor, etc." target="_blank" rel="noopener">ANSI escape</a> sequences. Modern features are auto-detected at startup using terminal queries (DA1, DA2, XTVERSION) and enabled when available:</p><ul><li><strong>Full support:</strong> Ghostty, Kitty, WezTerm, <a href="https://iterm2.com/" class="hover-link" data-tooltip="macOS terminal emulator with rich feature set — Sixel, imgcat, tmux integration, shell integration." target="_blank" rel="noopener">iTerm2</a></li><li><strong>Good support:</strong> Alacritty, Windows Terminal, Hyper</li><li><strong>Basic support:</strong> Terminal.app, older xterm builds</li></ul><p>Auto-detected features include <a href="/guide/kitty-protocol" class="hover-link" data-tooltip="Modern keyboard input protocol with key release events, modifiers, and full Unicode support">Kitty keyboard protocol</a>, truecolor, <a href="/reference/terminal-protocols" class="hover-link" data-tooltip="DEC mode 2026 — wraps frame emission so the terminal paints atomically. Prevents tearing in tmux, Zellij, and other multiplexers.">synchronized output</a>, graphics protocols, and clipboard access. See <a href="https://terminfo.dev" target="_blank" rel="noreferrer">terminfo.dev</a> for detailed compatibility data across terminal emulators.</p><h2 id="how-does-theming-work-in-silvery" tabindex="-1">How does theming work in Silvery? <a class="header-anchor" href="#how-does-theming-work-in-silvery" aria-label="Permalink to &quot;How does theming work in Silvery?&quot;">​</a></h2><p>Silvery ships 38 color palettes with semantic tokens:</p><div class="language-tsx vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">tsx</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Box</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> borderStyle</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;round&quot;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> borderColor</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;$primary&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  &lt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Text</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> color</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;$success&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;Saved&lt;/</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Text</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  &lt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Text</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> color</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;$muted&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;Last updated 2 min ago&lt;/</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Text</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;/</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Box</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span></code></pre></div><p>Themes auto-detect the terminal&#39;s background color (via OSC 11 query) and adjust for WCAG-compliant contrast. Use <code>ThemeProvider</code> to set a palette globally, or override per-component.</p><p>See the <a href="/guide/styling.html">styling guide</a> for token reference and the <a href="/themes.html">theme explorer</a> to preview all 38 palettes.</p><h2 id="is-silvery-production-ready" tabindex="-1">Is Silvery production-ready? <a class="header-anchor" href="#is-silvery-production-ready" aria-label="Permalink to &quot;Is Silvery production-ready?&quot;">​</a></h2><p>Silvery is actively developed and used in production by a complex TUI application with thousands of nodes, multiple views, and rich interactions. The rendering pipeline is exercised by property-invariant fuzz tests that verify idempotence, no-op stability, inverse operations, and <span class="glossary-hint" data-tooltip="The visible portion of the terminal — rows × cols currently displayed to the user">viewport</span> clipping.</p><p>The API surface is stabilizing but may have breaking changes before 1.0. If you&#39;re building something that needs long-<span class="glossary-hint" data-tooltip="Terminal abstraction — wraps I/O, styling (chalk-compatible), capabilities, and dimensions">term</span> API stability, pin your version and watch the changelog.</p><h2 id="does-silvery-have-typescript-support" tabindex="-1">Does Silvery have TypeScript support? <a class="header-anchor" href="#does-silvery-have-typescript-support" aria-label="Permalink to &quot;Does Silvery have TypeScript support?&quot;">​</a></h2><p>Silvery is written entirely in TypeScript with strict mode enabled. All components, hooks, and APIs are fully typed. The package ships TypeScript source directly -- no compiled JavaScript, no type declaration files. This means you get full type information including inline documentation in your editor.</p><h2 id="how-does-the-layout-engine-work" tabindex="-1">How does the layout engine work? <a class="header-anchor" href="#how-does-the-layout-engine-work" aria-label="Permalink to &quot;How does the layout engine work?&quot;">​</a></h2><p>Silvery uses <a href="https://beorn.codes/flexily" target="_blank" rel="noreferrer">Flexily</a>, a <a href="/guide/layout-engine" class="hover-link" data-tooltip="Facebook&#39;s WASM-based flexbox layout engine — alternative to Flexily">Yoga</a>-compatible flexbox layout engine written in pure TypeScript. The key difference from other terminal frameworks:</p><ol><li><strong>Layout runs first</strong> -- <a href="https://beorn.codes/flexily" class="hover-link" data-tooltip="Pure JavaScript flexbox layout engine — powers Silvery&#39;s layout system" target="_blank" rel="noopener">Flexily</a> calculates positions and sizes before React renders components</li><li><strong>Components access dimensions</strong> -- <code>useBoxRect()</code> provides width, height, x, y during <a href="/api/render" class="hover-link" data-tooltip="Mount a React tree into a terminal with incremental rendering">render</a></li><li><strong>Flexbox model</strong> -- standard CSS flexbox properties (<code>flexDirection</code>, <code>justifyContent</code>, <code>alignItems</code>, <code>flexGrow</code>, <code>flexShrink</code>, <code>gap</code>, etc.)</li><li><strong>No <a href="/guide/silvery-vs-ink#performance-size" class="hover-link" data-tooltip="WebAssembly — Ink uses Yoga compiled to WASM for layout. Silvery uses pure TypeScript (Flexily) by default, with optional Yoga WASM.">WASM</a></strong> -- pure TypeScript, 2.5× faster than <a href="/guide/layout-engine" class="hover-link" data-tooltip="Facebook&#39;s WASM-based flexbox layout engine — alternative to Flexily">Yoga</a> <a href="/guide/silvery-vs-ink#performance-size" class="hover-link" data-tooltip="WebAssembly — Ink uses Yoga compiled to WASM for layout. Silvery uses pure TypeScript (Flexily) by default, with optional Yoga WASM.">WASM</a> for typical terminal layouts</li></ol><p>This enables responsive layouts (columns that adapt to terminal width), native <code>overflow=&quot;scroll&quot;</code> containers, and automatic text truncation -- all without post-<a href="/api/render" class="hover-link" data-tooltip="Mount a React tree into a terminal with incremental rendering">render</a> measurement.</p><h2 id="can-i-use-silvery-for-fullscreen-terminal-apps" tabindex="-1">Can I use Silvery for fullscreen terminal apps? <a class="header-anchor" href="#can-i-use-silvery-for-fullscreen-terminal-apps" aria-label="Permalink to &quot;Can I use Silvery for fullscreen terminal apps?&quot;">​</a></h2><p>Yes. Silvery supports two modes:</p><ul><li><strong>Fullscreen</strong> (default) -- <a href="/guide/silvery-vs-ink#rendering" class="hover-link" data-tooltip="DEC private mode 1049 — a separate terminal buffer apps can take over (like vim). No scrollback, but full cell-level control. Also called alt-screen.">alternate screen</a> buffer, absolute positioning, incremental diff. Best for interactive apps (editors, dashboards, games).</li><li><strong>Inline</strong> -- normal <a href="/guide/scrolling" class="hover-link" data-tooltip="Terminal history buffer above the visible viewport — content that scrolled off-screen">scrollback</a>, relative positioning. Best for CLIs that output results and exit, or tools that mix interactive and scrolling output.</li></ul><p>Both modes use <span class="glossary-hint" data-tooltip="Only re-rendering cells that changed between frames — 100x+ faster than full redraws">incremental rendering</span> for efficient updates. The mode is set at startup and affects only the <span class="glossary-hint" data-tooltip="Final rendering stage — diffs terminal buffers and emits minimal ANSI escape sequences">output phase</span>, not components or state management.</p><h2 id="how-do-i-migrate-from-ink-to-silvery" tabindex="-1">How do I migrate from Ink to Silvery? <a class="header-anchor" href="#how-do-i-migrate-from-ink-to-silvery" aria-label="Permalink to &quot;How do I migrate from Ink to Silvery?&quot;">​</a></h2><p>Three steps:</p><ol><li><strong>Swap imports</strong> -- replace <code>ink</code> with <code>silvery/ink</code> and <code>chalk</code> with <code>silvery/chalk</code></li><li><strong>Run your tests</strong> — ~99% of <a href="/guide/silvery-vs-ink" class="hover-link" data-tooltip="React-based terminal UI framework by Vadim Demedes — the established standard for React CLIs">Ink</a> 7.0&#39;s test suite (918/931) passes with the compatibility layer</li><li><strong>Adopt native APIs gradually</strong> -- use <code>useBoxRect()</code> for responsive layouts, replace manual key handlers with <code>SelectList</code>, add themes with semantic tokens</li></ol><p>The compatibility layer is a bridge, not a destination. New code should use Silvery&#39;s native APIs to get the full benefit of layout-first rendering and the component library.</p><p>See the <a href="/getting-started/migrate-from-ink.html">migration guide</a> for detailed instructions and common patterns.</p>`,67)])])}const m=t(o,[["render",r]]);export{u as __pageData,m as default};
